class Solution {
    public boolean canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) return true;
        if ((1 + maxChoosableInteger) * maxChoosableInteger / 2 < desiredTotal) return false;
        return dfs(0, desiredTotal, maxChoosableInteger, new boolean[1 << (maxChoosableInteger + 1)]);
    }

    private boolean dfs(int used, int total, int maxChoosableInteger, boolean[] memo) {
        if (total <= 0) return false;
        if (memo[used]) return memo[used - 1];
        for (int i = 1; i <= maxChoosableInteger; i++) {
            if (((used >> i) & 1) == 0) {
                if (!dfs(used | (1 << i), total - i, maxChoosableInteger, memo)) {
                    memo[used] = true;
                    return true;
                }
            }
        }
        memo[used] = false;
        return false;
    }
}
